import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;

public class DatabaseConnector {

	private static final String URL =
		"jdbc:postgresql://localhost:5432/mydatabase";
	private static final String USER = "admin";
	private static final String PASSWORD = "admin";

	public static void main(String[] args) {
		try (
			Connection connection = DriverManager.getConnection(URL, USER, PASSWORD)
		) {
			connection.setAutoCommit(false);
			try (Statement statement = connection.createStatement()) {
				statement.execute(
					"CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY, username VARCHAR(255) NOT NULL)"
				);
				statement.executeUpdate("INSERT INTO users (username) VALUES ('johndoe')");
				ResultSet resultSet = statement.executeQuery("SELECT * FROM users");
				while (resultSet.next()) {
					System.out.println(
						"User ID: " +
							resultSet.getInt("id") +
							", Username: " +
							resultSet.getString("username")
					);
				}
				connection.commit();
			} catch (SQLException e) {
				connection.rollback();
				throw e;
			}
		} catch (SQLException ex) {
			ex.printStackTrace();
		}
	}
}

import jakarta.persistence.*; // Para las anotaciones JPA
import org.hibernate.Session;
import org.hibernate.SessionFactory;
import org.hibernate.cfg.Configuration;
import org.hibernate.query.Query;

@Entity
@Table(name = "users")
class User {

	@Id
	@GeneratedValue(strategy = GenerationType.IDENTITY)
	private int id;

	@Column(name = "username")
	private String username;

	@Column(name = "full_name")
	private String fullName;

	// Constructor vacío
	public User() {}

	// Constructor con parámetros
	public User(String username, String fullName) {
		this.username = username;
		this.fullName = fullName;
	}

	// Getters y setters
	public int getId() {
		return id;
	}

	public void setId(int id) {
		this.id = id;
	}

	public String getUsername() {
		return username;
	}

	public void setUsername(String username) {
		this.username = username;
	}

	public String getFullName() {
		return fullName;
	}

	public void setFullName(String fullName) {
		this.fullName = fullName;
	}
}

public class HibernateExample {

	public static void main(String[] args) {
		// Configuración y creación de una SessionFactory
		SessionFactory factory = new Configuration()
			.configure("hibernate.cfg.xml")
			.addAnnotatedClass(User.class)
			.buildSessionFactory();

		// Creación de una sesión
		Session session = factory.openSession();

		try {
			// Iniciando una transacción
			session.beginTransaction();

			// Guardar un objeto
			User newUser = new User("johndoe", "John Doe");
			session.save(newUser);

			// Consulta de objetos
			Query<User> query = session.createQuery(
				"from User where username = 'johndoe'",
				User.class
			);
			User user = query.uniqueResult();

			System.out.println("User: " + user.getUsername());

			// Comprometer la transacción
			session.getTransaction().commit();
		} catch (Exception e) {
			e.printStackTrace();
			session.getTransaction().rollback();
		} finally {
			session.close();
			factory.close();
		}
	}
}
